Rule.Source:
  import sailpoint.object.Application;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.IdentityEntitlement;
  import sailpoint.object.Link;
  import sailpoint.object.ManagedAttribute;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.TaskResult;
  import sailpoint.api.Terminator;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  private static Log log = LogFactory.getLog("ascension.rule.setWGMembers");

  log.debug("Start Refresh Workgroups From AD Groups");
  
  String appName = null;
  String wgName = null;
  String adGrpDisplayName = null;
  
  if(config!=null){
    appName = config.get("appName");
    wgName = config.get("wgName");
    adGrpDisplayName = config.get("adGrpDisplayName");
  } 		


  int countAdded = 0;
  int countRemoved = 0;

  // A string to append our task results to as we process.
  String resultString = "";

  //check if application exist
  Application app = context.getObjectByName(Application.class, appName);
  if (null == app) {
    String errMsg = "ERROR: Could not find AD application named: " + appName; 
    log.debug(errMsg);
    log.error(errMsg);
    resultString += errMsg + "\n";
    taskResult.addMessage(resultString);
    return resultString;
  }
  resultString += "Processing Workgroup memberships from application [" + appName + "]\n";

  //Get Managed Attribte for the AD group
  QueryOptions opManagedAttrs = new QueryOptions();
  opManagedAttrs.setCloneResults(true);
  opManagedAttrs.addFilter(Filter.eq("application", app));
  opManagedAttrs.addFilter(Filter.eq("displayName", adGrpDisplayName));

  Iterator it = null;
  try {
    it = context.search(ManagedAttribute.class, opManagedAttrs);
  } catch (sailpoint.tools.GeneralException ge) {
    resultString += ge.getMessage() + "\n";
    taskResult.addMessage(resultString);
    return resultString;
  }

  while ((null != it) && (it.hasNext())) {
    //iterate through managed attributes, there should only be one
    ManagedAttribute ma = it.next();
    log.debug("Got Managed Attribute id:" + ma.getId() + " Managed Attribute Display Name:" + ma.getDisplayName());

    //get the WorkGroups
    Identity wg = context.getObjectByName(Identity.class, wgName);
    if (null == wg) {

      String errMsg = "WARNING: Could not find workgroup named: " + wgName + ", skipping.";
      log.debug(errMsg);
      log.error(errMsg);
      resultString += errMsg + "\n";
      resultString += "WARNING:   Please add this workgroup to IIQ";
      taskResult.addMessage(resultString);
      // Skip the to the next ManagedAttribute in the while() loop.
      continue;       
    }

    log.debug("Workgroup name:" + wg.getName());
    resultString += "AD group [" + ma.getDisplayName() + "] drives Workgroup [" + wgName + "]\n";

    // Get the identities that should be in the Workgroup based on AD's "member"
    QueryOptions ops = new QueryOptions();
    ops.setCloneResults(true);
    ops.add(Filter.eq("value", ma.getValue()));


    HashSet haveWorkgroup = new HashSet(); //gets identities which are currently in workgroup
    HashSet shouldHaveWorkgroup = new HashSet(); //identities which should be member of workgroup as they are member of AD entitlement
    HashSet removeWorkgroup = new HashSet(); //identities to be removed from workgroup
    HashSet addWorkgroup = new HashSet();	//identities to be added to the workgroup

    Iterator itr = context.search(IdentityEntitlement.class,ops);
    if(itr !=  null && itr.hasNext()) {
      while ( itr.hasNext() ) {
        IdentityEntitlement identEnt = (IdentityEntitlement) itr.next();
        Identity idShould = identEnt.getIdentity();
        log.debug("ID Should ID:" + idShould.getName());
        shouldHaveWorkgroup.add(idShould);
      }
      log.debug("Identities Should size:" + shouldHaveWorkgroup.size());
    } else {
      log.debug("Members was null");       
    }
    sailpoint.tools.Util.flushIterator(itr);

    //identities which are currently in workgroup
    QueryOptions qoHave = new QueryOptions();
    qoHave.setCloneResults(true);
    qoHave.addFilter(Filter.eq("workgroups.id", wg.getId()));
    Iterator itHave = context.search(Identity.class, qoHave);
    while (itHave.hasNext()) {
      Identity idHave = itHave.next();
      haveWorkgroup.add(idHave);
      resultString += " - Identity " + idHave.getName() + " currently has membership.\n";
    }
    sailpoint.tools.Util.flushIterator(itHave);

    log.debug("Identities Have size:" + haveWorkgroup.size());

    //add identities which are currently not in workgroup
    for (Identity id : shouldHaveWorkgroup) {
      if (!haveWorkgroup.contains(id)) {
        addWorkgroup.add(id);
        resultString += " - Identity " + id.getName() + " will be given membership.\n";
      }
    }

    //remove identies no longer in AD group from Workgroup
    for (Identity id : haveWorkgroup) {
      if (!shouldHaveWorkgroup.contains(id)) {
        removeWorkgroup.add(id);
        resultString += " - Identity " + id.getName() + " will removed from workgroup.\n";
      }
    }

    log.debug("Removing workgroup from identities");
    for (Identity id : removeWorkgroup) {
      id.remove(wg);
      context.saveObject(id);
      String message = " - Removed user: " + id.getName() + " from workgroup: " + wg.getName(); 
      log.debug(message);          
      resultString += message + "\n";
    }

    log.debug("Adding workgroup to identities");
    for (Identity id : addWorkgroup) {
      id.add(wg);
      context.saveObject(id);
      String message = " - Added user: " + id.getName() + " to workgroup:" + wg.getName();
      log.debug(message);          
      resultString += message + "\n";
    }

    countAdded = addWorkgroup.size();
    countRemoved = removeWorkgroup.size();

    // Commit all the changes to the particular identities for this Workgroup.
    context.saveObject(wg);
    context.commitTransaction();
//    context.decache();
    resultString += " - workgroup changes committed to the database.\n";  

  }

  context.commitTransaction();

  //TaskResult taskResult = context.getObjectByName(TaskResult.class,"Ascension-TaskDefinition-RunRule-SetWorkgroupMembership");

  if(result != null) {
    taskResult.setAttribute("countAdded",countAdded);
    taskResult.setAttribute("countRemoved",countRemoved);

  }

  resultString += "identities added to Workgroup: "+countAdded; 
  resultString += "identities removed from Workgroup: "+countRemoved; 
  return resultString;

  Terminator termin = new sailpoint.api.Terminator(context);

  log.debug("End Refresh Workgroups From AD Groups");
